// WebSocket Server
class Server<T extends WebSocket = WebSocket> extends EventEmitter {
    options: ServerOptions;
    path: string;
    clients: Set<T>;

    constructor(options?: ServerOptions, callback?: () => void);

    address(): AddressInfo | string;
    close(cb?: (err?: Error) => void): void;
    handleUpgrade(
        request: IncomingMessage,
        socket: Duplex,
        upgradeHead: Buffer,
        callback: (client: T, request: IncomingMessage) => void,
    ): void;
    shouldHandle(request: IncomingMessage): boolean | Promise<boolean>;

    // Events
    on(event: "connection", cb: (this: Server<T>, socket: T, request: IncomingMessage) => void): this;
    on(event: "error", cb: (this: Server<T>, error: Error) => void): this;
    on(event: "headers", cb: (this: Server<T>, headers: string[], request: IncomingMessage) => void): this;
    on(event: "close" | "listening", cb: (this: Server<T>) => void): this;
    on(event: string | symbol, listener: (this: Server<T>, ...args: any[]) => void): this;

    once(event: "connection", cb: (this: Server<T>, socket: T, request: IncomingMessage) => void): this;
    once(event: "error", cb: (this: Server<T>, error: Error) => void): this;
    once(event: "headers", cb: (this: Server<T>, headers: string[], request: IncomingMessage) => void): this;
    once(event: "close" | "listening", cb: (this: Server<T>) => void): this;
    once(event: string | symbol, listener: (this: Server<T>, ...args: any[]) => void): this;

    off(event: "connection", cb: (this: Server<T>, socket: T, request: IncomingMessage) => void): this;
    off(event: "error", cb: (this: Server<T>, error: Error) => void): this;
    off(event: "headers", cb: (this: Server<T>, headers: string[], request: IncomingMessage) => void): this;
    off(event: "close" | "listening", cb: (this: Server<T>) => void): this;
    off(event: string | symbol, listener: (this: Server<T>, ...args: any[]) => void): this;

    addListener(event: "connection", cb: (client: T, request: IncomingMessage) => void): this;
    addListener(event: "error", cb: (err: Error) => void): this;
    addListener(event: "headers", cb: (headers: string[], request: IncomingMessage) => void): this;
    addListener(event: "close" | "listening", cb: () => void): this;
    addListener(event: string | symbol, listener: (...args: any[]) => void): this;

    removeListener(event: "connection", cb: (client: T) => void): this;
    removeListener(event: "error", cb: (err: Error) => void): this;
    removeListener(event: "headers", cb: (headers: string[], request: IncomingMessage) => void): this;
    removeListener(event: "close" | "listening", cb: () => void): this;
    removeListener(event: string | symbol, listener: (...args: any[]) => void): this;
}

handleRequest(req: SSEPushRequest | WebSocketPushRequest, res: PushResponse) {
	const {
		ws,
		query: { pushRef },
		user,
		headers,
	} = req;

	let connectionError = '';

	const expectedOriginResult = this.constructExpectedOrigin(req);

	if (!pushRef) {
		connectionError = 'The query parameter "pushRef" is missing!';
	} else if (!expectedOriginResult.success) {
		this.logger.warn('Origin header is missing');

		connectionError = 'Invalid origin!';
	} else if (
		inProduction &&
		headers.origin?.toLowerCase() !== expectedOriginResult.expectedOrigin.toLowerCase()
	) {
		this.logger.warn(
			`Origin header does NOT match the expected origin. (Origin: "${headers.origin}", Expected: "${expectedOriginResult.expectedOrigin}")`,
			{
				expectedOrigin: expectedOriginResult.expectedOrigin,
				headers: {
					host: req.headers.host,
					origin: req.headers.origin,
					['x-forwarded-proto']: req.headers['x-forwarded-proto'],
					['x-forwarded-host']: req.headers['x-forwarded-host'],
				},
			},
		);
		connectionError = 'Invalid origin!';
	}

	if (connectionError) {
		if (ws) {
			ws.send(connectionError);
			ws.close(1008);
			return;
		}
		throw new BadRequestError(connectionError);
	}

	if (req.ws) {
		(this.backend as WebSocketPush).add(pushRef, user.id, req.ws);
	} else if (!this.useWebSockets) {
		(this.backend as SSEPush).add(pushRef, user.id, { req, res });
	} else {
		res.status(401).send('Unauthorized');
		return;
	}

	this.emit('editorUiConnected', pushRef);
}

