private depthFirstSearchRecursive(
	from: INode,
	fn: (node: INode) => boolean,
	seen: Set<INode>,
): INode | undefined {
	if (seen.has(from)) {
		return undefined;
	}
	seen.add(from);

	if (fn(from)) {
		return from;
	}

	for (const childConnection of this.getDirectChildConnections(from)) {
		const found = this.depthFirstSearchRecursive(childConnection.to, fn, seen);

		if (found) {
			return found;
		}
	}

	return undefined;
}

